diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index cb346be8ffe5..e3ecf90613e1 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7295,15 +7295,54 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
       }
       if (Instruction *UI = GetInstructionForCost(&R))
         SeenInstrs.insert(UI);
+    
+  // If the VPlan contains recipes that are uniform-after-vectorization,
+  // it means VPlan can execute them fewer times (e.g. hoisted or single-lane),
+  // which is an additional simplification not accounted for in the legacy model.
+  auto Iter2 = vp_depth_first_deep(Plan.getVectorLoopRegion()->getEntry());
+  for (VPBasicBlock *VPBB2 : VPBlockUtils::blocksOnly<VPBasicBlock>(Iter2)) {
+    for (VPRecipeBase &R2 : *VPBB2) {
+      if (auto *RepR = dyn_cast<VPReplicateRecipe>(&R2)) {
+        if (RepR->isUniform())
+          return true;
+      }
     }
   }
+}
+  }

   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
   return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx,
                                     TheLoop](BasicBlock *BB) {
-    return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop, BB](Instruction &I) {
+    
+  // Consider loop-invariant instructions inside conditionally executed blocks
+  // that don't have corresponding recipes as additional simplifications.
+  // This approximates cases where VPlan hoists/sinks invariants out of a
+  // predicated triangle and thus differs from the legacy instruction-level view.
+  for (BasicBlock *BB : TheLoop->blocks()) {
+    // Skip header phi handling and latch as before; focus on inner conditional blocks.
+    if (BB == TheLoop->getHeader() || BB == TheLoop->getLoopLatch())
+      continue;
+    // If the block ends with a conditional branch, it is likely part of a predicated region.
+    if (auto *Br = dyn_cast<BranchInst>(BB->getTerminator())) {
+      if (Br->isConditional()) {
+        for (Instruction &I : *BB) {
+          if (isa<PHINode>(&I))
+            continue;
+          // Treat loop-invariant instructions without a corresponding recipe and not skipped
+          // for VPlan cost computation as extra simplifications.
+          if (TheLoop->isLoopInvariant(&I) &&
+              !SeenInstrs.contains(&I) &&
+              !CostCtx.skipCostComputation(&I, /*IsVector=*/true)) {
+            return true;
+          }
+        }
+      }
+    }
+  }
+return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop, BB](Instruction &I) {
       if (isa<PHINode>(&I) && BB == TheLoop->getHeader())
         return false;
       return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);

